sql:
SELECT DISTINCT driver_id
FROM rides
WHERE date BETWEEN '2023-01-01' AND '2023-01-31';

SELECT SUM(rides) AS total_rides
FROM rides
WHERE date BETWEEN '2013-01-01' AND '2013-01-07';

SELECT DISTINCT date_from
FROM daily_stats
ORDER BY date_from;

SELECT date
  FROM rides
  ORDER BY date ASC;

SELECT date
FROM rides
WHERE rides = (SELECT MAX(rides) FROM rides);

SELECT ride_id
FROM rides
WHERE rating = (SELECT MAX(rating) FROM rides);

